script:
frappe.ui.form.on("Transport Fee", {
    student: function(frm) {

        if (!frm.doc.student) {
            return;
        }

        frappe.db.get_list("Student Transport Assignment", {
            filters: {
                student: frm.doc.student,
                is_active: 1
            },
            fields: [
                "name",
                "monthly_fee"
            ],
            limit: 1
        }).then((records) => {

            if (records.length > 0) {

                frm.set_value("transport_assignment", records[0].name);
                frm.set_value("amount", records[0].monthly_fee);

            } else {

                frm.set_value("transport_assignment", "");
                frm.set_value("amount", "");

                frappe.msgprint(
                    __("No Active Transport Assignment found for this student.")
                );
            }

        });

    }
});
